## Code Example
```c
typedef struct Node { struct Node *next; void *block; } Node;
typedef struct FreeList { _Atomic(Node*) head; } FreeList;
void* alloc(FreeList *f) {
  Node *n = atomic_load(&f->head);
  while (n && !atomic_compare_exchange_weak(&f->head, &n, n->next));
  return n ? n->block : NULL;
}
```

