// skeleton structures (conceptual)
typedef struct timer {
  uint64_t due;        // absolute microsecond timestamp
  uint64_t id;         // unique identifier
  void (*cb)(void*);   // callback
  void *ctx;             // user data
  struct timer *next;    // linked list within bucket
} timer_t;

typedef struct timer_wheel {
  // per-core buckets, each bucket is a lock-free list
  bucket_t *buckets; // sized per wheel
  // mapping from id -> timer for cancellation (lock-free)
  atomic<uint64_t> active_id; // simplified placeholder
} timer_wheel;

void add_timer(timer_wheel* w, uint64_t due, uint64_t id, void (*cb)(void*), void* ctx);
